import React, { useEffect, useState } from 'react';
import Navbar from '../../components/Navbar';
import api from '../../api/axiosInstance';
import styles from './AdminPages.module.css';

const ManageUsersPage = () => {
  const [users, setUsers]   = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError]     = useState('');

  const load = () => {
    setLoading(true);
    api.get('/users')                          // backend must expose GET /api/users (admin)
      .then((res) => setUsers(res.data?.data || []))
      .catch(() => setError('Failed to load users (ensure GET /api/users admin route exists).'))
      .finally(() => setLoading(false));
  };

  useEffect(load, []);

  const toggleActive = async (id, current) => {
    try {
      await api.put(`/users/${id}`, { isActive: !current });
      load();
    } catch { alert('Update failed.'); }
  };

  return (
    <>
      <Navbar />
      <div className={styles.page}>
        <h1>👤 Manage Users</h1>
        {loading && <p>Loading…</p>}
        {error   && <p style={{ color: 'orange' }}>{error}</p>}
        {!loading && !error && (
          <table className={styles.table}>
            <thead>
              <tr>
                <th>Name</th>
                <th>Email</th>
                <th>Role</th>
                <th>Status</th>
                <th>Action</th>
              </tr>
            </thead>
            <tbody>
              {users.length === 0 ? (
                <tr><td colSpan={5}>No users found.</td></tr>
              ) : users.map((u) => (
                <tr key={u._id}>
                  <td>{u.name}</td>
                  <td>{u.email}</td>
                  <td>
                    <span className={`${styles.badge} ${u.role === 'admin' ? styles.badgeBlue : styles.badgeGreen}`}>
                      {u.role}
                    </span>
                  </td>
                  <td>
                    <span className={`${styles.badge} ${u.isActive ? styles.badgeGreen : styles.badgeRed}`}>
                      {u.isActive ? 'Active' : 'Inactive'}
                    </span>
                  </td>
                  <td>
                    <button
                      className={`${styles.btnSm} ${u.isActive ? styles.btnDanger : styles.btnSuccess}`}
                      onClick={() => toggleActive(u._id, u.isActive)}
                    >
                      {u.isActive ? 'Deactivate' : 'Activate'}
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </>
  );
};

export default ManageUsersPage;
